INSERT INTO `page` VALUES (2,'2026-04-02 13:56:45.884400','User(email=admin 20024, password=null, fullName=null, avatar=null, role=2)','2026-04-02 13:56:45.884400','User(email=admin 20024, password=null, fullName=null, avatar=null, role=2)',0,1,3,'Weiss\' face showed an extremely surprised expression.\n\n\"It\'s so fragrant. This is the first time I\'ve smelled such an attractive aroma.\"\n\n\"Lord Wang Ting, what is the name of this delicacy?\"\n\nFor Weiss, who loves food and is also a foodie, there is absolutely no resistance in the face of such food.\n\n\"Weiss, what did I say?\"\n\nWeiss, immersed in the food, immediately nodded.\n\n\"Hmm, no problem.\"\n\nWeiss agreeing to his request without any hesitation was obviously expected by him.\n\n\"Is he the same as Pike?\"\n\nSeeing Weiss\' small steps, Wang Ting felt speechless, and at this moment, Beerus was also attracted by the fragrance.\n\nThen he saw the food in front of Weiss and immediately yelled, \"Weiss, you actually eat alone.\"\n\nThe two started arguing. Of course, this had nothing to do with Wang Ting, because his goal had already been achieved.\n\nRoar.\n\nWeiss\'s voice echoed throughout the God of Destruction\'s realm.\n\n\"Weiss.\"\n\nDuring the conversation between Wang Ting and Weiss, Beerus asked softly, \"Weiss, what are you talking about with the lord?\"\n\n\"Why do I feel like there is some secret being hidden from me?\"\n\n\"Lord Wang Ting lacks an opponent. Aren\'t you the best candidate?\"\n\n\"Nanny?\"\n\n\"Why do I feel like I\'ve been tricked again?\"\n\nIt was Wang Ting and Weiss, the Angel of Universe Seven.\n\nIn the next second, Wang Ting suddenly erupted and instantly transformed into a Super Saiyan 4, and his golden aura continued to rise.\n\n\"Not bad.\"\n\nWeiss looked at Wang Ting, who had transformed in an instant, and at this moment, Weiss already knew his combat strength.\n\nAlthough Wang Ting\'s strength has reached the level of a weaker God of Destruction, he is still a little weak in his opinion, but considering Wang Ting\'s age, he can indeed be regarded as a genius.\n\nGoku and Vegeta, who were watching the battle below, were also staring at the two people in the air with their eyes fixed.\n\nSon Gohan clenched his fists tightly, and his heart was extremely eager for strength at this moment.\n\nAlthough Lord Wang Ting\'s strength is...',1),(6,'2026-04-14 13:30:28.162377','User(email=admin 20024, password=null, fullName=null, avatar=null, location=null, learningLevel=null, role=2)','2026-04-14 13:30:28.162377','User(email=admin 20024, password=null, fullName=null, avatar=null, location=null, learningLevel=null, role=2)',0,2,3,'string',2),(7,'2026-04-14 13:33:14.576579','User(email=admin 20024, password=null, fullName=null, avatar=null, location=null, learningLevel=null, role=2)','2026-04-14 13:33:14.576579','User(email=admin 20024, password=null, fullName=null, avatar=null, location=null, learningLevel=null, role=2)',0,2,4,'string',1);
